'use client';
import { useJobs } from '@/hooks/useJobs';
import { JobCard } from './JobCard';
import { Job } from '@/types/jobs';

function EmptyState({ icon, title, subtitle }: { icon: string; title: string; subtitle: string }) {
  return (
    <div className="py-16 text-center">
      <div className="text-4xl mb-4">{icon}</div>
      <p className="text-[#4a3728] font-semibold mb-1">{title}</p>
      <p className="text-[#6b5847] text-sm">{subtitle}</p>
    </div>
  );
}

function SectionHeader({ title, count, badge }: { title: string; count?: number; badge?: string }) {
  return (
    <div className="flex items-center gap-2.5 mb-4">
      <h2 className="text-[#4a3728] font-bold text-base">{title}</h2>
      {count !== undefined && count > 0 && (
        <span className="px-2 py-0.5 rounded-md bg-[#e0d8cf] text-[#6b5847] text-xs font-semibold">{count}</span>
      )}
      {badge && (
        <span className="px-2 py-0.5 rounded-md bg-[#4a3728]/8 text-[#4a3728] text-xs font-semibold border border-[#4a3728]/15">
          {badge}
        </span>
      )}
    </div>
  );
}

function JobGrid({ jobs }: { jobs: Job[] }) {
  return (
    <div className="grid grid-cols-1 xl:grid-cols-2 gap-3">
      {jobs.map((job) => <JobCard key={job.id} job={job} />)}
    </div>
  );
}

export function JobSections() {
  const { filteredJobs, featuredJobs, recentJobs, savedJobObjects, appliedJobObjects, activeSection, filters } = useJobs();

  const isFiltering = filters.search || filters.types.length || filters.experience.length ||
    filters.workMode.length || filters.categories.length || filters.location;

  if (isFiltering) {
    return (
      <div>
        <SectionHeader title="Search Results" count={filteredJobs.length} />
        {filteredJobs.length === 0
          ? <EmptyState icon="🔍" title="No jobs match your search" subtitle="Try adjusting your filters or search terms" />
          : <JobGrid jobs={filteredJobs} />}
      </div>
    );
  }

  if (activeSection === 'saved') {
    return (
      <div>
        <SectionHeader title="Saved Jobs" count={savedJobObjects.length} />
        {savedJobObjects.length === 0
          ? <EmptyState icon="◈" title="No saved jobs yet" subtitle="Bookmark jobs you're interested in to find them here" />
          : <JobGrid jobs={savedJobObjects} />}
      </div>
    );
  }

  if (activeSection === 'applied') {
    return (
      <div>
        <SectionHeader title="Applied Jobs" count={appliedJobObjects.length} />
        {appliedJobObjects.length === 0
          ? <EmptyState icon="◉" title="No applications yet" subtitle="Jobs you apply to will show up here" />
          : <JobGrid jobs={appliedJobObjects} />}
      </div>
    );
  }

  if (activeSection === 'recent') {
    return (
      <div>
        <SectionHeader title="Recently Posted" count={recentJobs.length} />
        <JobGrid jobs={recentJobs} />
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {featuredJobs.length > 0 && (
        <section>
          <SectionHeader title="Recommended for You" count={featuredJobs.length} badge="✦ Curated" />
          <JobGrid jobs={featuredJobs} />
        </section>
      )}
      <section>
        <SectionHeader title="Recently Posted" count={recentJobs.length} />
        <JobGrid jobs={recentJobs} />
      </section>
      {(['Engineering', 'Design', 'Product'] as const).map((cat) => {
        const catJobs = filteredJobs.filter((j) => j.category === cat).slice(0, 4);
        if (!catJobs.length) return null;
        return (
          <section key={cat}>
            <SectionHeader title={`${cat} Roles`} count={catJobs.length} />
            <JobGrid jobs={catJobs} />
          </section>
        );
      })}
    </div>
  );
}